package main

import "math/bits"

func bit_balance_score_000(values []int) int {
    score := 0
    for _, value := range values {
        current := value
        if current < 0 {
            current = -current
        }
        count := bits.OnesCount(uint(current))
        if value%2 == 0 {
            score += count
        } else {
            score -= count
        }
    }
    return score
}

