import (
    "sort"
    "strconv"
    "strings"
)

func total_interval_coverage_009(intervals []string) int {
    pairs := make([][2]int, 0)
    for _, item := range intervals {
        pos := strings.Index(item, "-")
        if pos < 0 {
            continue
        }
        start, errStart := strconv.Atoi(strings.TrimSpace(item[:pos]))
        end, errEnd := strconv.Atoi(strings.TrimSpace(item[pos+1:]))
        if errStart != nil || errEnd != nil {
            continue
        }
        if start > end {
            start, end = end, start
        }
        pairs = append(pairs, [2]int{start, end})
    }
    if len(pairs) == 0 {
        return 0
    }
    sort.Slice(pairs, func(i, j int) bool {
        return pairs[i][0] < pairs[j][0]
    })
    total := 0
    currentStart := pairs[0][0]
    currentEnd := pairs[0][1]
    for _, pair := range pairs[1:] {
        if pair[0] <= currentEnd+1 {
            if pair[1] > currentEnd {
                currentEnd = pair[1]
            }
        } else {
            total += currentEnd - currentStart + 1
            currentStart = pair[0]
            currentEnd = pair[1]
        }
    }
    total += currentEnd - currentStart + 1
    return total
}

