            continue
        }
        left, errLeft := strconv.Atoi(strings.TrimSpace(line[:pos]))
        right, errRight := strconv.Atoi(strings.TrimSpace(line[pos+1:]))
        if errLeft != nil || errRight != nil {
            continue
        }
        if int(math.Abs(float64(left-right))) <= window && left%2 == right%2 {
            count++
        }
    }
    return count
}

