class Solution {
    public static int shortest_grid_path_028(List<String> grid) {
        int startRow = -1;
        int startCol = -1;
        int endRow = -1;
        int endCol = -1;
        for (int row = 0; row < grid.size(); row++) {
            String line = grid.get(row);
            for (int col = 0; col < line.length(); col++) {
                if (line.charAt(col) == 'S') {
                    startRow = row;
                    startCol = col;
                } else if (line.charAt(col) == 'E') {
                    endRow = row;
                    endCol = col;
                }
            }
