            continue
        }
        count, err := strconv.Atoi(parts[2])
        if err != nil || count < 0 {
            continue
        }
        current := inventory[parts[1]]
        if parts[0] == "add" {
            inventory[parts[1]] = current + count
        } else if parts[0] == "remove" {
            if current-count < 0 {
                inventory[parts[1]] = 0
            } else {
                inventory[parts[1]] = current - count
            }
        }
    }
    total := 0
    for _, value := range inventory {
        total += value
    }
