        action, item, raw_count = parts
        try:
            count = int(raw_count)
        except ValueError:
            continue
        if count < 0:
            continue
        if action == "add":
            inventory[item] = inventory.get(item, 0) + count
        elif action == "remove":
            inventory[item] = max(0, inventory.get(item, 0) - count)
